import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] darr = new long[n];
        for (int i = 0; i < n; i++) {
            darr[i] = computeDepth(nums[i]);
        }

        int numK = 6;
        Fenw[] fenwArr = new Fenw[numK];
        for (int k = 0; k < numK; k++) {
            fenwArr[k] = new Fenw(n);
        }

        for (int i = 0; i < n; i++) {
            long d = darr[i];
            if (d >= 0 && d < numK) {
                fenwArr[(int)d].update(i, 1);
            }
        }

        List<Long> ansList = new ArrayList<>();
        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                if (k >= 0 && k < numK) {
                    long res = fenwArr[k].queryRange(l, r);
                    ansList.add(res);
                } else {
                    ansList.add(0L);
                }
            } else if (q[0] == 2) {
                int idx = (int) q[1];
                long val = q[2];
                long oldDepth = darr[idx];
                long newDepth = computeDepth(val);
                darr[idx] = newDepth;
                if (oldDepth >= 0 && oldDepth < numK) {
                    fenwArr[(int) oldDepth].update(idx, -1);
                }
                if (newDepth >= 0 && newDepth < numK) {
                    fenwArr[(int) newDepth].update(idx, 1);
                }
            }
        }

        long[] resArr = new long[ansList.size()];
        for (int i = 0; i < ansList.size(); i++) {
            resArr[i] = ansList.get(i);
        }
        return resArr;
    }

    private static long computeDepth(long x) {
        if (x == 1) {
            return 0;
        }
        long steps = 0;
        long t = x;
        while (t != 1) {
            t = Long.bitCount(t);
            steps++;
        }
        return steps;
    }

    static class Fenw {
        private long[] tree;
        private int n;

        public Fenw(int n) {
            this.n = n;
            this.tree = new long[n + 1];
        }

        public void update(int index, long delta) {
            int idx = index + 1;
            while (idx <= n) {
                tree[idx] += delta;
                idx += (idx & -idx);
            }
        }

        public long query(int index) {
            if (index < 0) return 0;
            long sum = 0;
            int idx = index + 1;
            while (idx > 0) {
                sum += tree[idx];
                idx -= (idx & -idx);
            }
            return sum;
        }

        public long queryRange(int l, int r) {
            if (l > r) return 0;
            long leftPart = l > 0 ? query(l - 1) : 0;
            long rightPart = query(r);
            return rightPart - leftPart;
        }
    }
}
