public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int[] depthSmall = new int[51];
        depthSmall[1] = 0;
        for (int i = 2; i <= 50; i++) {
            int pop = Integer.bitCount(i);
            depthSmall[i] = 1 + depthSmall[pop];
        }

        int n = nums.length;
        FenwickTree[] trees = new FenwickTree[6];
        for (int i = 0; i < 6; i++) {
            trees[i] = new FenwickTree(n);
        }

        int[] depthArr = new int[n];
        for (int i = 0; i < n; i++) {
            depthArr[i] = computeDepth(nums[i], depthSmall);
            if (depthArr[i] < 6) {
                trees[depthArr[i]].update(i, 1);
            }
        }

        List<Long> ansList = new ArrayList<>();
        for (long[] q : queries) {
            if (q[0] == 1) {
                int l = (int)q[1];
                int r = (int)q[2];
                int k = (int)q[3];
                if (k >= 0 && k < 6) {
                    ansList.add(trees[k].rangeSum(l, r));
                } else {
                    ansList.add(0L);
                }
            } else if (q[0] == 2) {
                int idx = (int)q[1];
                long val = q[2];
                int oldDepth = depthArr[idx];
                if (oldDepth < 6) {
                    trees[oldDepth].update(idx, -1);
                }
                int newDepth = computeDepth(val, depthSmall);
                depthArr[idx] = newDepth;
                if (newDepth < 6) {
                    trees[newDepth].update(idx, 1);
                }
            }
        }

        long[] res = new long[ansList.size()];
        for (int i = 0; i < res.length; i++) {
            res[i] = ansList.get(i);
        }
        return res;
    }

    private static int computeDepth(long x, int[] depthSmall) {
        if (x == 1) {
            return 0;
        }
        if (x <= 50) {
            return depthSmall[(int)x];
        }
        long pop = Long.bitCount(x);
        return 1 + depthSmall[(int)pop];
    }

    static class FenwickTree {
        int n;
        long[] tree;

        public FenwickTree(int n) {
            this.n = n;
            tree = new long[n + 1];
        }

        public void update(int index, long delta) {
            int i = index + 1;
            while (i <= n) {
                tree[i] += delta;
                i += (i & -i);
            }
        }

        public long query(int index) {
            if (index < 0) {
                return 0;
            }
            int i = index + 1;
            long sum = 0;
            while (i > 0) {
                sum += tree[i];
                i -= (i & -i);
            }
            return sum;
        }

        public long rangeSum(int l, int r) {
            if (l > r) {
                return 0;
            }
            return query(r) - query(l - 1);
        }
    }
}
