import java.util.*;

public class Solution {

    public static long[] solve(long[] nums, long[][] queries) {
        int maxPre = 60;
        int[] preDepth = new int[maxPre + 1];
        for (int i = 1; i <= maxPre; i++) {
            if (i == 1) {
                preDepth[i] = 0;
            } else {
                int bits = Integer.bitCount(i);
                preDepth[i] = preDepth[bits] + 1;
            }
        }

        int n = nums.length;
        Fenw[] fenw = new Fenw[6];
        for (int i = 0; i < 6; i++) {
            fenw[i] = new Fenw(n);
        }

        int[] currentDepth = new int[n];
        for (int i = 0; i < n; i++) {
            int d = getDepth(nums[i], preDepth);
            currentDepth[i] = d;
            if (d >= 0 && d < 6) {
                fenw[d].update(i, 1);
            }
        }

        List<Long> ansList = new ArrayList<>();

        for (long[] q : queries) {
            int type = (int) q[0];
            if (type == 1) {
                int l = (int) q[1];
                int r = (int) q[2];
                int k = (int) q[3];
                if (k < 0 || k >= 6) {
                    ansList.add(0L);
                } else {
                    long cnt = fenw[k].query(l, r);
                    ansList.add(cnt);
                }
            } else if (type == 2) {
                int idx = (int) q[1];
                long val = q[2];
                int old_d = currentDepth[idx];
                int new_d = getDepth(val, preDepth);
                if (old_d != new_d) {
                    if (old_d >= 0 && old_d < 6) {
                        fenw[old_d].update(idx, -1);
                    }
                    if (new_d >= 0 && new_d < 6) {
                        fenw[new_d].update(idx, 1);
                    }
                    currentDepth[idx] = new_d;
                }
            }
        }

        long[] ans = new long[ansList.size()];
        for (int i = 0; i < ansList.size(); i++) {
            ans[i] = ansList.get(i);
        }
        return ans;
    }

    private static int getDepth(long x, int[] preDepth) {
        if (x == 1) {
            return 0;
        }
        int bits = Long.bitCount(x);
        if (x <= 60) {
            return preDepth[(int) x];
        } else {
            return 1 + preDepth[bits];
        }
    }

    static class Fenw {
        long[] tree;
        int n;

        public Fenw(int n) {
            this.n = n;
            this.tree = new long[n + 1];
        }

        void update(int index, long delta) {
            int i = index + 1;
            while (i <= n) {
                tree[i] += delta;
                i += i & -i;
            }
        }

        long prefix(int index) {
            if (index < 0) {
                return 0;
            }
            long sum = 0;
            int i = index + 1;
            while (i > 0) {
                sum += tree[i];
                i -= i & -i;
            }
            return sum;
        }

        long query(int l, int r) {
            return prefix(r) - prefix(l - 1);
        }
    }
}
